import React, { useState } from 'react';
import { loginAdmin } from '../../services/api';
import { FaEnvelope, FaLock, FaArrowRight, FaGoogle, FaLinkedin, FaGithub } from 'react-icons/fa';
import { MdAnalytics, MdSpeed, MdSecurity } from 'react-icons/md';

const LoginPage = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      // Using email as username for the API
      const response = await loginAdmin(email, password);
      if (response.data.access_token) {
        onLogin(response.data.access_token);
      }
    } catch (err) {
      setError('Invalid credentials! Use varshini / varshu');
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      position: 'relative',
      padding: '20px',
      overflow: 'hidden'
    }}>
      {/* Background Image */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundImage: 'url("https://images.unsplash.com/photo-1497366216548-37526070297c?ixlib=rb-4.0.3&auto=format&fit=crop&w=2070&q=80")',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat',
        filter: 'brightness(0.7)'
      }}></div>

      {/* Overlay */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: 'linear-gradient(135deg, rgba(102, 126, 234, 0.9) 0%, rgba(118, 75, 162, 0.9) 100%)'
      }}></div>

      {/* Main Card */}
      <div style={{
        display: 'flex',
        maxWidth: '1200px',
        width: '100%',
        background: 'white',
        borderRadius: '20px',
        overflow: 'hidden',
        boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
        minHeight: '600px',
        position: 'relative',
        zIndex: 1
      }}>
        {/* Left Side - Hero Section with Pattern Overlay */}
        <div style={{
          flex: 1,
          background: 'linear-gradient(135deg, rgba(102, 126, 234, 0.95) 0%, rgba(118, 75, 162, 0.95) 100%)',
          padding: '50px 40px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'space-between',
          color: 'white',
          position: 'relative',
          overflow: 'hidden'
        }}>
          {/* Left side background pattern */}
          <div style={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundImage: 'url("https://www.transparenttextures.com/patterns/cubes.png")',
            opacity: 0.1,
            pointerEvents: 'none'
          }}></div>

          <div style={{ position: 'relative', zIndex: 1 }}>
            <div style={{
              display: 'flex',
              alignItems: 'center',
              gap: '10px',
              marginBottom: '60px'
            }}>
              <div style={{
                width: '40px',
                height: '40px',
                background: 'rgba(255,255,255,0.2)',
                borderRadius: '10px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '24px'
              }}>
                🤖
              </div>
              <span style={{
                fontSize: '20px',
                fontWeight: 'bold'
              }}>AI-Resume</span>
            </div>

            <h1 style={{
              fontSize: '42px',
              fontWeight: 'bold',
              marginBottom: '20px',
              lineHeight: '1.2'
            }}>
              AI-Powered Resume Screening Made Simple
            </h1>

            <p style={{
              fontSize: '18px',
              opacity: 0.95,
              marginBottom: '50px',
              lineHeight: '1.6'
            }}>
              Analyze, rank and hire the best candidates faster with the power of AI.
            </p>

            {/* Features */}
            <div style={{
              display: 'flex',
              flexDirection: 'column',
              gap: '20px'
            }}>
              <div style={{
                display: 'flex',
                alignItems: 'center',
                gap: '15px'
              }}>
                <div style={{
                  width: '40px',
                  height: '40px',
                  background: 'rgba(255,255,255,0.2)',
                  borderRadius: '10px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}>
                  <MdAnalytics size={24} />
                </div>
                <div>
                  <div style={{ fontWeight: 'bold', marginBottom: '5px' }}>Smart Analytics</div>
                  <div style={{ fontSize: '14px', opacity: 0.9 }}>Real-time candidate insights</div>
                </div>
              </div>

              <div style={{
                display: 'flex',
                alignItems: 'center',
                gap: '15px'
              }}>
                <div style={{
                  width: '40px',
                  height: '40px',
                  background: 'rgba(255,255,255,0.2)',
                  borderRadius: '10px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}>
                  <MdSpeed size={24} />
                </div>
                <div>
                  <div style={{ fontWeight: 'bold', marginBottom: '5px' }}>Fast Processing</div>
                  <div style={{ fontSize: '14px', opacity: 0.9 }}>Screen resumes in seconds</div>
                </div>
              </div>

              <div style={{
                display: 'flex',
                alignItems: 'center',
                gap: '15px'
              }}>
                <div style={{
                  width: '40px',
                  height: '40px',
                  background: 'rgba(255,255,255,0.2)',
                  borderRadius: '10px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}>
                  <MdSecurity size={24} />
                </div>
                <div>
                  <div style={{ fontWeight: 'bold', marginBottom: '5px' }}>Secure & Reliable</div>
                  <div style={{ fontSize: '14px', opacity: 0.9 }}>Enterprise-grade security</div>
                </div>
              </div>
            </div>
          </div>

          <div style={{
            fontSize: '14px',
            opacity: 0.8,
            marginTop: '50px',
            position: 'relative',
            zIndex: 1
          }}>
            <p>© 2024 AI Resume Screening System. All rights reserved.</p>
          </div>
        </div>

        {/* Right Side - Login Form */}
        <div style={{
          flex: 1,
          padding: '50px 40px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          background: 'white'
        }}>
          <div>
            <div style={{
              marginBottom: '40px'
            }}>
              <h2 style={{
                fontSize: '32px',
                color: '#333',
                marginBottom: '10px',
                fontWeight: 'bold'
              }}>
                Admin Login
              </h2>
              <p style={{
                color: '#666',
                fontSize: '16px'
              }}>
                Welcome back! Please login to continue.
              </p>
            </div>

            {error && (
              <div style={{
                background: '#fee',
                color: '#c33',
                padding: '12px',
                borderRadius: '8px',
                marginBottom: '20px',
                fontSize: '14px',
                border: '1px solid #fcc'
              }}>
                {error}
              </div>
            )}

            <form onSubmit={handleSubmit}>
              {/* Email Field */}
              <div style={{
                marginBottom: '25px'
              }}>
                <label style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: '#555',
                  fontWeight: '500',
                  fontSize: '14px'
                }}>
                  Email Address
                </label>
                <div style={{
                  position: 'relative'
                }}>
                  <FaEnvelope style={{
                    position: 'absolute',
                    left: '15px',
                    top: '50%',
                    transform: 'translateY(-50%)',
                    color: '#999',
                    fontSize: '18px'
                  }} />
                  <input
                    type="email"
                    placeholder="Enter your email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    style={{
                      width: '100%',
                      padding: '14px 15px 14px 45px',
                      border: '1px solid #e0e0e0',
                      borderRadius: '10px',
                      fontSize: '15px',
                      outline: 'none',
                      transition: 'all 0.3s'
                    }}
                    required
                    disabled={loading}
                    onFocus={(e) => e.target.style.borderColor = '#667eea'}
                    onBlur={(e) => e.target.style.borderColor = '#e0e0e0'}
                  />
                </div>
              </div>

              {/* Password Field */}
              <div style={{
                marginBottom: '15px'
              }}>
                <label style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: '#555',
                  fontWeight: '500',
                  fontSize: '14px'
                }}>
                  Password
                </label>
                <div style={{
                  position: 'relative'
                }}>
                  <FaLock style={{
                    position: 'absolute',
                    left: '15px',
                    top: '50%',
                    transform: 'translateY(-50%)',
                    color: '#999',
                    fontSize: '18px'
                  }} />
                  <input
                    type="password"
                    placeholder="Enter your password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    style={{
                      width: '100%',
                      padding: '14px 15px 14px 45px',
                      border: '1px solid #e0e0e0',
                      borderRadius: '10px',
                      fontSize: '15px',
                      outline: 'none',
                      transition: 'all 0.3s'
                    }}
                    required
                    disabled={loading}
                    onFocus={(e) => e.target.style.borderColor = '#667eea'}
                    onBlur={(e) => e.target.style.borderColor = '#e0e0e0'}
                  />
                </div>
              </div>

              {/* Forgot Password */}
              <div style={{
                textAlign: 'right',
                marginBottom: '30px'
              }}>
                <a href="#" style={{
                  color: '#667eea',
                  textDecoration: 'none',
                  fontSize: '14px',
                  fontWeight: '500'
                }}>
                  Forgot Password?
                </a>
              </div>

              {/* Login Button */}
              <button
                type="submit"
                disabled={loading}
                style={{
                  width: '100%',
                  padding: '14px',
                  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '10px',
                  fontSize: '16px',
                  fontWeight: '600',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '10px',
                  transition: 'transform 0.2s'
                }}
                onMouseEnter={(e) => e.target.style.transform = 'translateY(-2px)'}
                onMouseLeave={(e) => e.target.style.transform = 'translateY(0)'}
              >
                {loading ? 'Logging in...' : 'Login'}
                {!loading && <FaArrowRight size={14} />}
              </button>

              {/* Divider */}
              <div style={{
                display: 'flex',
                alignItems: 'center',
                margin: '30px 0',
                gap: '15px'
              }}>
                <div style={{
                  flex: 1,
                  height: '1px',
                  background: '#e0e0e0'
                }}></div>
                <span style={{
                  color: '#999',
                  fontSize: '13px'
                }}>Or continue with</span>
                <div style={{
                  flex: 1,
                  height: '1px',
                  background: '#e0e0e0'
                }}></div>
              </div>

              {/* Social Login Buttons */}
              <div style={{
                display: 'flex',
                gap: '15px',
                justifyContent: 'center'
              }}>
                <button
                  type="button"
                  style={{
                    flex: 1,
                    padding: '12px',
                    border: '1px solid #e0e0e0',
                    borderRadius: '10px',
                    background: 'white',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: '10px',
                    transition: 'all 0.3s'
                  }}
                  onMouseEnter={(e) => e.target.style.background = '#f5f5f5'}
                  onMouseLeave={(e) => e.target.style.background = 'white'}
                >
                  <FaGoogle color="#db4437" />
                  <span style={{ fontSize: '14px' }}>Google</span>
                </button>
                <button
                  type="button"
                  style={{
                    flex: 1,
                    padding: '12px',
                    border: '1px solid #e0e0e0',
                    borderRadius: '10px',
                    background: 'white',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: '10px',
                    transition: 'all 0.3s'
                  }}
                  onMouseEnter={(e) => e.target.style.background = '#f5f5f5'}
                  onMouseLeave={(e) => e.target.style.background = 'white'}
                >
                  <FaLinkedin color="#0077b5" />
                  <span style={{ fontSize: '14px' }}>LinkedIn</span>
                </button>
                <button
                  type="button"
                  style={{
                    flex: 1,
                    padding: '12px',
                    border: '1px solid #e0e0e0',
                    borderRadius: '10px',
                    background: 'white',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: '10px',
                    transition: 'all 0.3s'
                  }}
                  onMouseEnter={(e) => e.target.style.background = '#f5f5f5'}
                  onMouseLeave={(e) => e.target.style.background = 'white'}
                >
                  <FaGithub color="#333" />
                  <span style={{ fontSize: '14px' }}>GitHub</span>
                </button>
              </div>

              {/* Demo Credentials */}
              <div style={{
                marginTop: '30px',
                padding: '15px',
                background: '#f8f9fa',
                borderRadius: '10px',
                textAlign: 'center'
              }}>
                <p style={{
                  fontSize: '13px',
                  color: '#666',
                  margin: 0
                }}>
                  🔐 Demo Credentials: <strong>varshini</strong> / <strong>varshu</strong>
                </p>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
